&lt;p&gt;&amp;#39;अहिंसा&amp;#39; शब्द में &lt;u&gt;&lt;strong&gt;&amp;#39;अ&amp;#39;&lt;/strong&gt;&lt;/u&gt; उपसर्ग है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;#39;अहिंसा&amp;#39; में&amp;nbsp;&lt;strong&gt;&lt;u&gt;&amp;#39;अ&amp;#39;&lt;/u&gt; &lt;/strong&gt;उपसर्ग है।

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;अ + हिंसा = अहिंसा&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&amp;lsquo;अ&amp;rsquo; हिंदी का&amp;nbsp;उपसर्ग शब्द है।&lt;/li&gt;
	&lt;li&gt;&amp;#39;अ&amp;#39; उपसर्ग&amp;nbsp;से बनने वाले कुछ शब्द - &lt;strong&gt;अनीति,&amp;nbsp;अटल,&amp;nbsp;अथाह&lt;/strong&gt;।&lt;/li&gt;
	&lt;li&gt;अन्य विकल्प गलत हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;&lt;u&gt;उपसर्ग&lt;/u&gt;&lt;/strong&gt;&lt;strong&gt;&amp;nbsp;-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;उपसर्ग शब्द के शुरूआत&amp;nbsp;में जुड़ते&amp;nbsp;हैं और&amp;nbsp;मूल शब्द का अर्थ बदल देते हैं।&lt;/li&gt;
	&lt;li&gt;उदाहरण :-&amp;nbsp;अप + यश =&amp;nbsp;अपयश,&amp;nbsp;अध + पका =&amp;nbsp;अधपका,&amp;nbsp;ना + लायक = नालायक,&amp;nbsp;हाफ + टिकट =&amp;nbsp;हाफटिकट आदि।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;हिन्दी में मुख्यतः&amp;nbsp;&lt;strong&gt;&lt;u&gt;चार प्रकार&lt;/u&gt;&lt;/strong&gt;&amp;nbsp;के उपसर्ग होते है :-
	&lt;ul&gt;
		&lt;li&gt;संस्कृत के उपसर्ग (&lt;strong&gt;प्र&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;परा&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;अप&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;सम्&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;अनु&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;अव&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;निस्&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;निर्&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;दुस्&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;दुर्&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;वि&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;आङ्&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;नि&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;अधि&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;अपि&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;अति&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;सु&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;उत्&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;अभि&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;प्रति&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;परि तथा उप&lt;/strong&gt;)&lt;/li&gt;
		&lt;li&gt;हिंदी के उपसर्ग (&lt;strong&gt;अन&lt;/strong&gt;&lt;strong&gt;,&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;अध&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;उन&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;औ&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;कु&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;चौ&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;पच&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;पर&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;बिन&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;भर&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;स&lt;/strong&gt;&lt;strong&gt;,&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;सह&lt;/strong&gt;&lt;strong&gt;,&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;चिर&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;न&lt;/strong&gt;&lt;strong&gt;,&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;बहु&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;आप&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;सम&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;दु&lt;/strong&gt;)&lt;/li&gt;
		&lt;li&gt;उर्दू के उपसर्ग&amp;nbsp;(&lt;strong&gt;ला&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;बद&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;बे&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;कम&lt;/strong&gt;&lt;strong&gt;,&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;ग़ैर&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;ना&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;खुश&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;हम&lt;/strong&gt;&lt;strong&gt;,&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;ऐन&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;सर&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;बेश&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;बा&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;अल&lt;/strong&gt;)&lt;/li&gt;
		&lt;li&gt;अंग्रेजी के उपसर्ग (&lt;strong&gt;ब&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;हाफ&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;को&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;हैड&lt;/strong&gt;&lt;strong&gt;, &lt;/strong&gt;&lt;strong&gt;वाइस&lt;/strong&gt;)&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;दिए गए विकल्पों में से सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 4 &amp;#39;सहेलियाँ&amp;#39;&lt;/span&gt;&amp;nbsp;है। अन्य विकल्प इसके गलत उत्तर हैं।&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिए गए विकल्पों में से &amp;#39;सहेली&amp;#39; शब्द का उचित बहुवचन शब्द &amp;#39;सहेलियाँ&amp;#39; है।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;सहेली के पर्यायवाची शब्द हैं -अलि, भटू, संगिनी, सहचारिणी, आली, सखी, सहचरी, सजनी, सैरन्ध्री।&lt;/li&gt;
	&lt;li&gt;&lt;font color=&quot;#202124&quot;&gt;अन्य विकल्प इसके अनुचित उत्तर हैं।&amp;nbsp;&lt;/font&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;background-color: rgb(255, 255, 255); width: 400px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td colspan=&quot;3&quot; style=&quot;width: 470px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;&lt;strong&gt;वचन -&lt;/strong&gt;&amp;nbsp;वचन का शाब्दिक अर्थ है &amp;ndash; संख्यावाचन। अर्थात शब्द के जिस रूप से उसके एक या अनेक होने का पता चले, वचन कहलाता है। इसके दो भेद हैं- एकवचन और बहुवचन।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 65px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;एकवचन&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 226px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;संज्ञा के जिस रूप से एक वस्तु, प्राणी या पदार्थ आदि का पता चलता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 180px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;लड़का, गाय, बेटी आदि।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 65px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;बहुवचन&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 226px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;संज्ञा के जिस रूप से एक से अधिक वस्तु, प्राणी या पदार्थ आदि का पता चलता है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 180px;&quot;&gt;
			&lt;p style=&quot;text-align: justify;&quot;&gt;लड़के, गायें, बेटियाँ आदि।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;दिए गए विकल्पों में से सही उत्तर&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विकल्प 1&amp;nbsp;&amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;विस्मयादिबोधक चिह्न&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;rsquo;&lt;/span&gt;&amp;nbsp;है। अन्य विकल्प इसके गलत उत्तर हैं।&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&amp;nbsp;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;आह्रादसूचक शब्दों, पदों और वाक्यों के अन्त में विस्मयादिबोधक चिह्न का प्रयोग होता है।&lt;/li&gt;
	&lt;li&gt;अपने से बड़े को सादर सम्बोधित करने में विस्मयादिबोधक चिह्न का प्रयोग होता है।&lt;/li&gt;
	&lt;li&gt;जहाँ अपने से छोटों के प्रति शुभकामनाएँ और सदभावनाएँ प्रकट की जाये, वहाँ विस्मयादिबोधक चिह्न का प्रयोग होता है।&lt;/li&gt;
	&lt;li&gt;जहाँ मन की हँसी-खुशी व्यक्त की जाय वहाँ विस्मयादिबोधक चिह्न का प्रयोग होता है।&lt;/li&gt;
	&lt;li&gt;संबोधनसूचक शब्द के बाद; विस्मयादिबोधक चिह्न का प्रयोग होता है।&lt;/li&gt;
	&lt;li&gt;अतिशयता को प्रकट करने के लिए कभी-कभी दो-तीन विस्मयादिबोधक चिह्नों का प्रयोग किया जाता है।&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;विस्मयादिबोधक चिह्न के उदाहरण :&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;​&lt;/span&gt;
		&lt;ol&gt;
			&lt;li&gt;अरे!, आप कौन हो!&lt;/li&gt;
			&lt;li&gt;हे राम, यह कैसे हुआ!&lt;/li&gt;
			&lt;li&gt;धिक्कार है तुम्हे!&lt;/li&gt;
			&lt;li&gt;हाय, मुझे देर हो गयी!&lt;/li&gt;
		&lt;/ol&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:330px;&quot; width=&quot;453&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 453px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;विराम चिह्न&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp; -&lt;/span&gt;&amp;nbsp;&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;विराम का अर्थ होता है - ठहराव । लिखते समय या बोलते समय यदि विराम न हो, तो पाठक या श्रोता को भाषा के सम्यक् ज्ञान में कठिनाई होती है। एक ही वाक्य के कई अर्थ निकल सकते हैं। वह भ्रमित हो सकता है।&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;जैसे --&lt;/span&gt;&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;उसे जैसे रोको , मत जाने दो । (रोकने की बात है ।)&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;हिंदी के विराम चिह्नों की श्रंखला इस प्रकार है -&amp;nbsp;&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;1). अल्पविराम (comma) --- ( , )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(2). अर्द्धविराम (semi colon) --- ( ; )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(3). पूर्णविराम (full stop) --- ( । )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(4). उपविराम (colon) --- ( : )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(5). प्रश्नवाचक-चिह्न (mark of interrogation) --- ( ? )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(6). विस्मयादिबोधक-चिह्न (mark of exclamation) --- ( ! )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(7). संयोजक-चिह्न (hyphen) --- ( - )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(8). उद्धरण- चिह्न (inverted commas) --- ( &amp;quot; &amp;quot; ) या ( &amp;#39; &amp;#39; )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(9). कोष्ठक-चिह्न (bracket) --- ( ( ) ) या ( [ ] )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(10). निर्देश-चिह्न (dash) ( _ )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(11). लोप-चिह्न (mark of elipses) --- ( ... ) या ( xxx )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(12). लाघव-चिह्न (mark of abbreviation) --- ( ॰ )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(13). पुनरुक्ति-चिह्न (mark of repetition) --- ( &amp;quot; &amp;quot; &amp;quot; )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(14). त्रुटि-चिह्न (mark of omission) --- ( ^ )&lt;/p&gt;

			&lt;p style=&quot;text-align: center;&quot;&gt;(15). विवरण-चिह्न (colon-dash) --- ( :- )&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;इसका सही उत्तर&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;&lt;/span&gt;&lt;strong&gt;प्राधिकरण​&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;strong&gt;&amp;#39;&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;span style=&quot;vertical-align: middle;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;#39;प्राधिकरण&amp;#39; का उचित अंग्रेजी शब्द है - &amp;#39;authorization​&amp;#39;।&lt;/li&gt;
&lt;/ul&gt;

