questions.statement:
&lt;p&gt;सूची-I के साथ सूची II का मिलान कीजिए।&lt;/p&gt;

&lt;p&gt;सूची-I (शब्द) &amp;mdash; सूची II (विलोम शब्द)&lt;br /&gt;
(A) साहस&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;(I)निरुत्साह&amp;nbsp;&lt;/p&gt;

&lt;p&gt;(B) स्पष्ट&amp;nbsp; &amp;nbsp; &amp;nbsp; &amp;nbsp;&amp;nbsp;&amp;nbsp;(II)&amp;nbsp;कायरता&amp;nbsp;&lt;/p&gt;

&lt;p&gt;(C) उत्साह&amp;nbsp; &amp;nbsp; &amp;nbsp; (III)&amp;nbsp;अस्पष्ट&amp;nbsp;&lt;/p&gt;

&lt;p&gt;(D) विस्तार&amp;nbsp; &amp;nbsp; &amp;nbsp;&amp;nbsp;(IV) संकुचन&lt;/p&gt;

questions.explanation:
&lt;p&gt;सही उत्तर&amp;nbsp;&lt;span style=&quot;color: rgb(32, 33, 36); font-variant-ligatures: none; letter-spacing: 0.1px; white-space-collapse: preserve;&quot;&gt;(A)-(II), (B)-(III), (C)-(1), (D)-(IV)&lt;/span&gt; है&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;height:170px;width:270px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 139px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;शब्द&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 278px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;परिभाषा&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 154px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;उदाहरण&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 139px;&quot;&gt;
			&lt;p style=&quot;margin-left: 4.9pt;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;विलोम&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;/&lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;विपरीतार्थक&lt;/span&gt;&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 278px;&quot;&gt;
			&lt;p style=&quot;margin-left: 4.35pt;&quot;&gt;विपरीत (उल्टा) अर्थ बताने वाले शब्दों को विलोम शब्द कहते हैं।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 154px;&quot;&gt;
			&lt;ol&gt;
				&lt;li&gt;रात - दिन&lt;/li&gt;
				&lt;li&gt;सुख - दुःख&lt;/li&gt;
			&lt;/ol&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;(A)&lt;strong&gt; साहस&lt;/strong&gt; का विलोम शब्द है&lt;strong&gt; कायरता&lt;/strong&gt;।&lt;/p&gt;

&lt;p&gt;साहस का अर्थ होता है बहादुरी या हिम्मत से काम लेना।&lt;br /&gt;
कायरता का अर्थ होता है डरपोक होना या साहस की कमी।&lt;br /&gt;
(B) &lt;strong&gt;स्पष्ट&lt;/strong&gt; का विलोम शब्द है &lt;strong&gt;अस्पष्ट&lt;/strong&gt;।&lt;/p&gt;

&lt;p&gt;स्पष्ट का अर्थ होता है साफ या चीज़ों को स्पष्ट रूप से बताना।&lt;br /&gt;
अस्पष्ट का अर्थ है धुंधला या समझ में न आना।&lt;br /&gt;
(C) &lt;strong&gt;उत्साह&lt;/strong&gt; का विलोम शब्द है&lt;strong&gt; निरुत्साह&lt;/strong&gt;।&lt;/p&gt;

&lt;p&gt;उत्साह का अर्थ होता है उत्तेजना, उर्जा या मनोबल से भरा होना।&lt;br /&gt;
निरुत्साह का अर्थ होता है उत्साह की कमी, निराशा।&lt;br /&gt;
(D)&lt;strong&gt; विस्तार&lt;/strong&gt; का विलोम शब्द है &lt;strong&gt;संकुचन&lt;/strong&gt;।&lt;/p&gt;

&lt;p&gt;विस्तार का अर्थ होता है फैलाव, चौड़ाई में बढ़ाव या अधिक स्थान लेना।&lt;br /&gt;
संकुचन का अर्थ होता है सिकुड़ना, कम होना या संकीर्ण होना।&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;सही उत्तर&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&lt;strong&gt;&amp;#39;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;जो देश के लिए सर्वस्व दे सकता है&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;strong&gt;&amp;#39;&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;है।&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;जो देश के लिए सर्वस्व दे सकता है&lt;/strong&gt;,&amp;nbsp;&lt;/span&gt;वही&amp;nbsp;&lt;span style=&quot;&quot;&gt;स्वाभिमान जी सकेगा&lt;/span&gt;।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(95, 99, 104);&quot;&gt;पद्यांश&amp;nbsp;की&lt;/span&gt;&amp;nbsp;पंक्ति,&lt;/li&gt;
	&lt;li&gt;
	&lt;p&gt;बलिदानों की बेला आई,&lt;/p&gt;

	&lt;p&gt;लोकतंत्र दे रहा दुहाई,&lt;/p&gt;

	&lt;p&gt;&lt;strong&gt;स्वाभिमान से वही जियेगा&lt;/strong&gt;&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;स्वाभिमान&amp;nbsp;&lt;/span&gt;का अर्थ:&amp;nbsp;अपनी जाति, राष्ट्र, धर्म आदि का सद् अभिमान&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&amp;#39;लोकतंत्र&amp;#39; &lt;/strong&gt;का विग्रह और समास होगा - लोक का तंत्र - तत्पुरुष&amp;nbsp;&lt;span style=&quot;&quot;&gt;समास&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;&quot;&gt;सही उत्तर&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;तर्कसंगत&amp;#39;&amp;nbsp;&lt;/span&gt;है।&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;देश के लिए &lt;strong&gt;&amp;#39;तर्कसंगत&amp;#39; &lt;/strong&gt;रणनीति &lt;/span&gt;होनी&amp;nbsp;&lt;span style=&quot;&quot;&gt;चाहिए&lt;/span&gt;।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;तर्कसंगत &lt;/strong&gt;का अर्थ: जो तर्क के आधार पर सिद्ध हो&lt;span style=&quot;&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;सही उत्तर&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;हिमालय-सी ऊँची धारणा&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;है।&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;धृति हिमगिरी-सी का भाव &amp;#39;&lt;strong&gt;हिमालय-सी ऊँची धारणा&amp;#39;&amp;nbsp;&lt;/strong&gt;से है।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(95, 99, 104);&quot;&gt;पद्यांश&amp;nbsp;की&lt;/span&gt;&amp;nbsp;पंक्ति,&lt;/li&gt;
	&lt;li&gt;
	&lt;p&gt;कृति तेजस्वी, &lt;strong&gt;धृति हिमगिरी-सी&lt;/strong&gt;&lt;/p&gt;

	&lt;p&gt;मुक्ति मांगती&amp;nbsp;गति अप्रतिहत।&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;सही उत्तर&lt;strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;&amp;#39;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;बाधा रहित गति&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;&amp;#39;गति अप्रतिहत&amp;#39; &lt;/strong&gt;&lt;/span&gt;का&lt;span style=&quot;&quot;&gt;&amp;nbsp;तात्पर्य &lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;बाधा रहित गति&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;&amp;nbsp;&lt;/span&gt;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;से&amp;nbsp;है।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(95, 99, 104);&quot;&gt;पद्यांश&amp;nbsp;की&lt;/span&gt;&amp;nbsp;पंक्ति,&lt;/li&gt;
	&lt;li&gt;
	&lt;p style=&quot;&quot;&gt;कृति तेजस्वी, धृति हिमगिरी-सी&lt;/p&gt;

	&lt;p style=&quot;&quot;&gt;मुक्ति मांगती &lt;strong&gt;गति अप्रतिहत&lt;/strong&gt;।&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;सही उत्तर&lt;strong&gt;&amp;nbsp;&amp;#39;&lt;span style=&quot;&quot;&gt;अवश्य प्राप्त होगा&lt;/span&gt;&amp;#39;&amp;nbsp;&lt;/strong&gt;है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;पद्यांश के अनुसार,&amp;nbsp;बलिदान से ही स्वतंत्रता का लक्ष्य &lt;strong&gt;&amp;#39;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;अवश्य प्राप्त होगा&amp;#39;&lt;/strong&gt;।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(95, 99, 104);&quot;&gt;पद्यांश&amp;nbsp;की&lt;/span&gt;&amp;nbsp;पंक्ति,&lt;/li&gt;
	&lt;li&gt;&amp;quot;बलिदानों की बेला आई,
	&lt;p&gt;लोकतंत्र दे रहा दुहाई,&lt;/p&gt;

	&lt;p&gt;स्वाभिमान से वही जियेगा&lt;/p&gt;
	जिससे कीमत गई चुकाई&amp;quot;&lt;/li&gt;
&lt;/ul&gt;
